def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            if cap == 0:
                priorities[i] = 0.0
            continue
        ratio = item / cap
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        additive = 0.0
        multiplicative = 1.0
        for j in range(1, 12):
            if j % 3 == 0:
                decay *= 0.85
            if ratio < (0.04 * j):
                base = (j ** 1.7) * (1 - ratio)**3 * decay
                if cap % (j+2) == 0:
                    base += np.cosh(j*0.1)
                else:
                    base -= np.tanh(j*0.3)
                score += base
            else:
                base = j * np.exp(-ratio * j) * decay / (j+2)
                if (cap + j*2) % 4 == 0:
                    base += np.sin(ratio * j * 1.5)
                else:
                    base -= np.cos(ratio * j * 1.1)
                score += base
            if j % 2 == 1:
                additive += np.tanh(score / (j + 1))
                multiplicative *= 1 + 0.1 * np.sin(score / (j + 1))
            else:
                additive -= np.arctan(score / (j + 1))
                multiplicative /= 1 + 0.05 * np.cos(score / (j + 1))
            if j == 7 and ratio > 0.8:
                multiplicative *= 0.95
            elif j == 10 and ratio < 0.3:
                multiplicative *= 1.1
        for k in range(1, 7):
            residual = cap - item * k
            if residual > 0:
                if residual % k == 0 or residual % (k+1) == 0:
                    score += np.log1p(residual) / (k + 0.7)
                    if residual % 5 == 0:
                        score += np.sqrt(residual) * 0.05
                else:
                    score -= (residual ** 0.3) / (k + 1.7)
            else:
                score -= abs(residual) * 0.15 * k
                if abs(residual) > item * 0.5:
                    score -= 0.5 * abs(residual)
        final_value = (score + additive) * multiplicative / (cap + 1)
        if final_value > 0:
            priorities[i] = -final_value * np.exp(-ratio*1.2) + np.sqrt(cap) * 0.01
        else:
            priorities[i] = -final_value * (np.log1p(cap) + np.cbrt(item)) - np.sin(cap * ratio)
    return priorities
